import time
from enum import Enum
import asyncio
import anthropic

class CircuitState(Enum):
    CLOSED = "closed"        # normal: calls pass through
    OPEN = "open"            # failing: fast-fail immediately
    HALF_OPEN = "half_open"  # probing: allow one call to test recovery

class ClaudeCircuitBreaker:
    def __init__(
        self,
        failure_threshold: int = 5,      # failures before opening
        success_threshold: int = 2,      # successes in half-open before closing
        cooldown_seconds: float = 30.0,  # time to wait before probing
    ):
        self._failure_threshold = failure_threshold
        self._success_threshold = success_threshold
        self._cooldown = cooldown_seconds
        self._state = CircuitState.CLOSED
        self._failure_count = 0
        self._success_count = 0
        self._opened_at: float | None = None

    @property
    def state(self) -> CircuitState:
        if (
            self._state == CircuitState.OPEN
            and self._opened_at is not None
            and time.monotonic() - self._opened_at > self._cooldown
        ):
            self._state = CircuitState.HALF_OPEN
            self._success_count = 0
        return self._state

    async def call(self, coro):
        if self.state == CircuitState.OPEN:
            raise RuntimeError("Claude circuit breaker OPEN — fast-failing request")

        try:
            result = await coro
            self._on_success()
            return result
        except (anthropic.RateLimitError, anthropic.InternalServerError, anthropic.APIConnectionError) as e:
            self._on_failure()
            raise

    def _on_success(self):
        self._failure_count = 0
        if self._state == CircuitState.HALF_OPEN:
            self._success_count += 1
            if self._success_count >= self._success_threshold:
                self._state = CircuitState.CLOSED

    def _on_failure(self):
        self._failure_count += 1
        if (
            self._state in (CircuitState.CLOSED, CircuitState.HALF_OPEN)
            and self._failure_count >= self._failure_threshold
        ):
            self._state = CircuitState.OPEN
            self._opened_at = time.monotonic()

# Module-level singleton
_breaker = ClaudeCircuitBreaker()

async def call_claude_guarded(messages: list[dict], max_tokens: int) -> str:
    return await _breaker.call(
        client.messages.create(model=MODEL.default, max_tokens=max_tokens, messages=messages)
    )

